package pe.org.camaracomercioica.protestos.security; import lombok.RequiredArgsConstructor; import org.springframework.beans.factory.annotation.Value; import org.springframework.security.oauth2.jwt.*; import org.springframework.stereotype.Service; import pe.org.camaracomercioica.protestos.dto.LoginResponse; import pe.org.camaracomercioica.protestos.model.Usuario; import java.time.*; import java.util.List; @Service @RequiredArgsConstructor public class JwtService { private final JwtEncoder encoder; @Value("${app.security.jwt.expiration-minutes:60}") private long expirationMinutes; @Value("${app.security.jwt.issuer:cci-protestos}") private String issuer; public LoginResponse issue(Usuario u){var now=Instant.now();var exp=now.plus(Duration.ofMinutes(expirationMinutes));var role=u.getRol().getNombre();var claims=JwtClaimsSet.builder().issuer(issuer).issuedAt(now).expiresAt(exp).subject(u.getEmail()).claim("roles",List.of(role)).build();var header=JwsHeader.with(org.springframework.security.oauth2.jose.jws.MacAlgorithm.HS256).build();var token=encoder.encode(JwtEncoderParameters.from(header,claims)).getTokenValue();return new LoginResponse(token,"Bearer",exp,new LoginResponse.UserView(u.getId(),u.getNombreCompleto(),u.getEmail(),List.of(role)));} }
